from fastapi import FastAPI, HTTPException


class UserService:
    def __init__(self):
        self.users = {}

    def create_user(self, body):
        # BUG: assumes 'email' is in body
        email = body['email']
        name = body.get('name', '')
        self.users[email] = name
        return {'email': email, 'name': name}


def make_handler():
    svc = UserService()
    return lambda body: svc.create_user(body)


def main():
    handler = make_handler()
    result = handler({'name': 'alice'})  # missing email
    print(result)


if __name__ == '__main__':
    main()
